import itertools
from math import gcd
from functools import reduce
class Solution:
    def maxGCDScore(self, nums, k):
        n = len(nums)
        best = 0
        for i in range(n):
            for j in range(i, n):
                sub = nums[i:j+1]
                L = len(sub)
                maxd = min(k, L)
                for d in range(0, maxd + 1):
                    for combo in itertools.combinations(range(L), d):
                        cs = set(combo)
                        arr = [sub[t] * 2 if t in cs else sub[t] for t in range(L)]
                        g = reduce(gcd, arr)
                        if L * g > best:
                            best = L * g
        return best

