from math import gcd
class Solution:
    def maxGCDScore(self, nums, k):
        def v2(x):
            c = 0
            while x % 2 == 0:
                x //= 2
                c += 1
            return c
        n = len(nums)
        best = 0
        for i in range(n):
            g = 0
            minv = None
            cnt = 0
            for j in range(i, n):
                x = nums[j]
                g = gcd(g, x)
                vx = v2(x)
                if minv is None or vx < minv:
                    minv = vx
                    cnt = 1
                elif vx == minv:
                    cnt += 1
                L = j - i + 1
                score = L * g
                if cnt <= k:
                    score = L * g * 2
                if score > best:
                    best = score
        return best

