var maxGCDScore = function(nums, k) {
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    const v2 = (x) => { let c = 0; while (x % 2 === 0) { x = Math.floor(x / 2); c++; } return c; };
    const n = nums.length;
    let best = 0;
    for (let i = 0; i < n; i++) {
        let g = 0;
        let minv = null;
        let cnt = 0;
        for (let j = i; j < n; j++) {
            const x = nums[j];
            g = gcd(g, x);
            const vx = v2(x);
            if (minv === null || vx < minv) { minv = vx; cnt = 1; }
            else if (vx === minv) cnt++;
            const L = j - i + 1;
            let score = L * g;
            if (cnt <= k) score = L * g * 2;
            if (score > best) best = score;
        }
    }
    return best;
};
